import heapq
from collections import defaultdict

class CriticalPathMethod:
    """Critical Path Method with Resource Leveling"""

    def __init__(self):
        self.tasks = {}
        self.dependencies = defaultdict(list)
        self.resources = {}  # resource requirements per task

    def add_task(self, task_id, duration, resources=None, predecessors=None):
        """
        Add task with duration and resource requirements
        resources: dict like {'developer': 2, 'designer': 1}
        """
        self.tasks[task_id] = {
            'duration': duration,
            'early_start': 0,
            'early_finish': 0,
            'late_start': float('inf'),
            'late_finish': float('inf'),
            'slack': 0
        }
        self.resources[task_id] = resources or {}

        if predecessors:
            for pred in predecessors:
                self.dependencies[pred].append(task_id)

    def calculate_schedule(self):
        """Calculate forward and backward pass for CPM"""
        # Forward pass - Early Start and Early Finish
        completed = set()
        in_progress = {}

        while len(completed) < len(self.tasks):
            # Find tasks ready to start
            ready = []
            for task in self.tasks:
                if task in completed:
                    continue
                preds = [dep for dep, succs in self.dependencies.items() 
                        if task in succs]
                if all(p in completed for p in preds):
                    ready.append(task)

            # Sort by early start
            ready.sort(key=lambda t: self.tasks[t]['early_start'])

            if not ready:
                break

            for task in ready:
                preds = [dep for dep, succs in self.dependencies.items() 
                        if task in succs]

                if not preds:
                    self.tasks[task]['early_start'] = 0
                else:
                    self.tasks[task]['early_start'] = max(
                        self.tasks[p]['early_finish'] for p in preds
                    )

                self.tasks[task]['early_finish'] = (
                    self.tasks[task]['early_start'] + self.tasks[task]['duration']
                )
                completed.add(task)

        # Backward pass - Late Start and Late Finish
        project_duration = max(t['early_finish'] for t in self.tasks.values())

        # Initialize with project end
        for task in self.tasks:
            self.tasks[task]['late_finish'] = project_duration

        # Process in reverse topological order
        reversed_order = sorted(self.tasks.keys(), 
                                key=lambda t: self.tasks[t]['early_start'], 
                                reverse=True)

        for task in reversed_order:
            successors = self.dependencies[task]

            if not successors:
                self.tasks[task]['late_finish'] = project_duration
            else:
                self.tasks[task]['late_finish'] = min(
                    self.tasks[s]['late_start'] for s in successors
                )

            self.tasks[task]['late_start'] = (
                self.tasks[task]['late_finish'] - self.tasks[task]['duration']
            )

            # Calculate slack
            self.tasks[task]['slack'] = (
                self.tasks[task]['late_start'] - self.tasks[task]['early_start']
            )

        return project_duration

    def get_critical_path(self):
        """Return tasks on critical path (slack = 0)"""
        return [t for t, data in self.tasks.items() if data['slack'] == 0]

    def resource_leveling(self, max_resources):
        """
        Simple resource leveling algorithm
        Delays non-critical tasks to smooth resource usage
        """
        project_duration = self.calculate_schedule()

        # Get all time slots
        schedule = []
        for task, data in self.tasks.items():
            for week in range(int(data['early_start']), int(data['early_finish'])):
                schedule.append((week, task))

        # Calculate resource usage per week
        resource_usage = defaultdict(lambda: defaultdict(int))
        for week, task in schedule:
            for res, count in self.resources[task].items():
                resource_usage[week][res] += count

        # Leveling: Delay tasks with slack to reduce peaks
        leveled_schedule = {}

        for task in self.tasks:
            if self.tasks[task]['slack'] > 0:
                # Try to shift within slack
                original_start = self.tasks[task]['early_start']

                for offset in range(int(self.tasks[task]['slack']) + 1):
                    new_start = original_start + offset
                    can_shift = True

                    for res, count in self.resources[task].items():
                        for w in range(int(new_start), 
                                      int(new_start + self.tasks[task]['duration'])):
                            current = resource_usage[w].get(res, 0)
                            if current + count > max_resources.get(res, float('inf')):
                                can_shift = False
                                break

                    if can_shift:
                        self.tasks[task]['early_start'] = new_start
                        self.tasks[task]['early_finish'] = (
                            new_start + self.tasks[task]['duration']
                        )
                        break

            leveled_schedule[task] = {
                'start': self.tasks[task]['early_start'],
                'finish': self.tasks[task]['early_finish'],
                'resources': self.resources[task]
            }

        return leveled_schedule

# Example: Software Development Project
if __name__ == "__main__":
    cpm = CriticalPathMethod()

    # Add tasks: (task_id, duration_weeks, resources, predecessors)
    cpm.add_task('A', 3, {'developer': 2}, None)           # Planning
    cpm.add_task('B', 4, {'developer': 3, 'designer': 1}, ['A'])  # Design
    cpm.add_task('C', 6, {'developer': 4}, ['B'])          # Backend
    cpm.add_task('D', 5, {'developer': 2, 'designer': 2}, ['B'])  # Frontend
    cpm.add_task('E', 3, {'tester': 2}, ['C', 'D'])        # Testing
    cpm.add_task('F', 2, {'developer': 1}, ['E'])          # Deployment

    print("=== Critical Path Method Analysis ===\n")

    project_duration = cpm.calculate_schedule()

    print(f"Project Duration: {project_duration} weeks\n")

    print("Task Schedule:")
    print("-" * 80)
    print(f"{'Task':<8} {'Dur':<5} {'ES':<5} {'EF':<5} {'LS':<5} {'LF':<5} "
          f"{'Slack':<8} {'Critical':<10}")
    print("-" * 80)

    critical_tasks = cpm.get_critical_path()

    for task_id in sorted(cpm.tasks.keys()):
        t = cpm.tasks[task_id]
        is_critical = "YES" if task_id in critical_tasks else "No"
        print(f"{task_id:<8} {t['duration']:<5} {t['early_start']:<5} "
              f"{t['early_finish']:<5} {t['late_start']:<5} "
              f"{t['late_finish']:<5} {t['slack']:<8} {is_critical:<10}")

    print("\n" + "=" * 80)
    print(f"Critical Path: {' -> '.join(critical_tasks)}")

    # Resource Leveling
    print("\n=== Resource Leveling ===\n")
    max_resources = {'developer': 5, 'designer': 2, 'tester': 2}

    leveled = cpm.resource_leveling(max_resources)

    print(f"Max Resources: {max_resources}\n")
    print("Leveled Schedule:")
    for task, info in leveled.items():
        print(f"  {task}: Week {info['start']:.0f} - {info['finish']:.0f} "
              f"(Resources: {info['resources']})")
